    "id": "continuous-melt-filter-scraper-blades",
    "name": "Скребковые лезвия для фильтров расплава",
    "fullName": "Премиальные скребковые лезвия и фильтрующие пластины для фильтров непрерывного расплава",
    "category": "granulator_blades",
    "sector": "recycling",
    "categoryDisplay": "Скребковые лезвия для фильтров расплава",
    "image": "/images/products/blades/scraper-blades.webp",
    "badge": "Переработка ПЦР",
